import { match } from "arktype"

try {
  const route = match({
    "string": (s) => `text:${s.length}`,
    "number": (n) => `num:${n}`,
    "string[]": (arr) => `list:${arr.length}`,
  })
  .case({
    kind: "'click'",
    target: {
      type: "'button'",
      id: "string"
    }
  }, (event) => `btn:${event.target.id}`)
  .case({
    kind: "'click'",
    target: {
      type: "'link'",
      href: "string.url"
    }
  }, (event) => `link:${event.target.href}`)
  .case({
    kind: "'submit'",
    payload: {
      formId: "string",
      valid: "boolean"
    }
  }, (event) => `submit:${event.payload.formId}:${event.payload.valid}`)
  .default("assert")

  console.log("Matcher created successfully!")

  // Test cases:
  console.log("1:", route("hello")) // text:5
  console.log("2:", route(42))      // num:42
  console.log("3:", route(["a", "b", "c"])) // list:3
  console.log("4:", route({ kind: "click", target: { type: "button", id: "btn-ok" } })) // btn:btn-ok
  console.log("5:", route({ kind: "click", target: { type: "link", href: "https://foo.com" } })) // link:https://foo.com
  console.log("6:", route({ kind: "submit", payload: { formId: "login", valid: true } })) // submit:login:true

  // Test invalid:
  try {
    route({ kind: "click", target: { type: "link", href: "not-a-url" } })
  } catch (err: any) {
    console.log("Expected Error (link invalid):", err.message)
  }

} catch (e: any) {
  console.error("Error creating matcher:", e)
}

